#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int c,t,n,m,fa[N],cnt;
string s;
bool vis[N*3];
int fun(int x)
{
	if(x==N-4||x==4-N) return x;
	if(vis[n-x+5]==1) return 0;
	if(x==0) return 0;
	if(vis[x+n+5]) return N-4;
	if(x<0&&(-x==fa[-x])) return x;
	if(x<0)
	{
		vis[x+n+5]=1;
		int tmp=fun(-fa[-x]);
		vis[x+n+5]=0;
		return tmp;
	}
	if(x==fa[x]) return x;
	vis[x+n+5]=1;
	fa[x]=fun(fa[x]);
	vis[x+n+5]=0;
	return fa[x];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".out","w",stdout);
	cin>>c>>t;
	while(t--)
	{
		cnt=0;
		cin>>n>>m;
		for(int i=1;i<=n;i++)
		{
			fa[i]=i;
		}
		for(int i=1;i<=m;i++)
		{
			cin>>s;
			int x,y;
			cin>>x;
			if(s=="T")
			{
				fa[x]=N-4;
			}
			else if(s=="F")
			{
				fa[x]=4-N;
			}
			else if(s=="U")
			{
				fa[x]=0;
			}
			else
			{
				cin>>y;
				if(s=="+")
				{
					fa[x]=fa[y];
				}
				else fa[x]=-fa[y];
			}
		}
		for(int i=1;i<=n;i++)
		{
			if(fun(i)==0) cnt++;
		}
		cout<<cnt<<"\n";
	}
	return 0;
}
